def catalog_category(brand_code):
    prefix=(brand_code or '').upper().split('-')[0]
    return {'CLK':'Clicker','TOP':'Top','EAR':'Orecchio','NIP':'Capezzolo','BEL':'Ombelico','LAB':'Labret','CUR':'Curved barbell','BAS':'Barbell e circolari','CHM':'Charm','PRD':'Componenti gioiello'}.get(prefix,'Gioielli')

def ensure_column(db, table, name, definition):
    if name not in [r["name"] for r in db.execute(f"PRAGMA table_info({table})").fetchall()]:
        db.execute(f"ALTER TABLE {table} ADD COLUMN {name} {definition}")

def init_db():
    with connect() as db:
        db.executescript("""
            CREATE TABLE IF NOT EXISTS users(
                id INTEGER PRIMARY KEY,
                username TEXT UNIQUE,
                password_hash TEXT
            );
            CREATE TABLE IF NOT EXISTS products(
                id INTEGER PRIMARY KEY,
                supplier_code TEXT UNIQUE,
                brand_code TEXT UNIQUE,
                quantity INTEGER,
                price REAL
            );
            CREATE TABLE IF NOT EXISTS audit_log(
                id INTEGER PRIMARY KEY,
                user_id INTEGER,
                username TEXT NOT NULL,
                action TEXT NOT NULL,
                product_id INTEGER,
                product_code TEXT,
                details TEXT,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP
            );
            CREATE TABLE IF NOT EXISTS sales(
                id INTEGER PRIMARY KEY,
                user_id INTEGER,
                username TEXT NOT NULL,
                product_id INTEGER NOT NULL,
                product_code TEXT NOT NULL,
                quantity INTEGER NOT NULL DEFAULT 1,
                unit_price REAL NOT NULL DEFAULT 0,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP
            );
            CREATE TABLE IF NOT EXISTS reorder_pending(
                product_id INTEGER PRIMARY KEY,
                quantity INTEGER NOT NULL DEFAULT 0
            );
            CREATE TABLE IF NOT EXISTS supplier_orders(
                id INTEGER PRIMARY KEY,
                order_number TEXT UNIQUE NOT NULL,
                status TEXT NOT NULL DEFAULT 'Generato',
                created_by TEXT NOT NULL,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP,
                received_at TEXT
            );
            CREATE TABLE IF NOT EXISTS supplier_order_items(
                id INTEGER PRIMARY KEY,
                order_id INTEGER NOT NULL,
                product_id INTEGER NOT NULL,
                supplier_code TEXT NOT NULL,
                quantity INTEGER NOT NULL
            );
            CREATE TABLE IF NOT EXISTS customer_orders(
                id INTEGER PRIMARY KEY,
                order_number TEXT UNIQUE NOT NULL,
                customer_name TEXT NOT NULL,
                customer_phone TEXT NOT NULL,
                customer_email TEXT,
                notes TEXT,
                status TEXT NOT NULL DEFAULT 'Nuovo',
                total REAL NOT NULL DEFAULT 0,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP
            );
            CREATE TABLE IF NOT EXISTS customer_order_items(
                id INTEGER PRIMARY KEY,
                order_id INTEGER NOT NULL,
                product_id INTEGER NOT NULL,
                product_code TEXT NOT NULL,
                quantity INTEGER NOT NULL,
                unit_price REAL NOT NULL
            );
            CREATE TABLE IF NOT EXISTS supplier_catalog(
                id INTEGER PRIMARY KEY,
                supplier_code TEXT UNIQUE NOT NULL,
                brand_code TEXT UNIQUE NOT NULL,
                category TEXT NOT NULL,
                supplier_price_usd REAL NOT NULL DEFAULT 0,
                sale_price_eur REAL NOT NULL DEFAULT 0,
                delivery_days TEXT NOT NULL DEFAULT '15–20 giorni',
                active INTEGER NOT NULL DEFAULT 1,
                excluded INTEGER NOT NULL DEFAULT 0
            );
            CREATE TABLE IF NOT EXISTS supplier_catalog_requests(
                id INTEGER PRIMARY KEY,
                request_number TEXT UNIQUE NOT NULL,
                catalog_id INTEGER NOT NULL,
                supplier_code TEXT NOT NULL,
                brand_code TEXT NOT NULL,
                customer_name TEXT NOT NULL,
                customer_phone TEXT NOT NULL,
                notes TEXT,
                quantity INTEGER NOT NULL DEFAULT 1,
                unit_price REAL NOT NULL,
                status TEXT NOT NULL DEFAULT 'Da ordinare',
                created_by TEXT NOT NULL,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP
            );
        """)
        for c,d in [("category","TEXT DEFAULT 'Altro'"),("photo_data","TEXT"),("material","TEXT"),("color","TEXT"),("size","TEXT"),("stone","TEXT"),("thread_type","TEXT"),("notes","TEXT"),("active","INTEGER NOT NULL DEFAULT 1"),("min_stock","INTEGER NOT NULL DEFAULT 1"),("location","TEXT"),("cost_price","REAL DEFAULT 0"),("is_new","INTEGER NOT NULL DEFAULT 0"),("is_bestseller","INTEGER NOT NULL DEFAULT 0"),("model_name","TEXT"),("variant_group","TEXT")]:
            ensure_column(db,"products",c,d)
        ensure_column(db,"users","role","TEXT NOT NULL DEFAULT 'seller'")
        ensure_column(db,"users","active","INTEGER NOT NULL DEFAULT 1")
        ensure_column(db,"users","created_at","TEXT DEFAULT CURRENT_TIMESTAMP")
        ensure_column(db,"sales","sale_number","TEXT")
        ensure_column(db,"sales","payment_method","TEXT DEFAULT 'Altro'")
        ensure_column(db,"sales","channel","TEXT DEFAULT 'Negozio'")
        ensure_column(db,"sales","status","TEXT DEFAULT 'Confermata'")
        for c,d in [("description","TEXT"),("size","TEXT"),("stone_color","TEXT"),("plating_color","TEXT"),("supplier_quantity","TEXT"),("image_file","TEXT"),("pdf_page","INTEGER")]:
            ensure_column(db,"supplier_catalog",c,d)
        u=os.environ.get("ADMIN_USERNAME","admin"); p=os.environ.get("ADMIN_PASSWORD","cambia-subito")
        db.execute("INSERT OR IGNORE INTO users(username,password_hash,role,active) VALUES(?,?,?,1)",(u,generate_password_hash(p),"admin"))
        db.execute("UPDATE users SET role='admin', active=1 WHERE username=?",(u,))
        # Conserva i dati esistenti e completa solo foto/campi mancanti.
        for supplier_code,brand_code,quantity,price,category,material,color,photo in SEED_PRODUCTS:
            db.execute("""INSERT OR IGNORE INTO products
                (supplier_code,brand_code,quantity,price,category,material,color,photo_data)
                VALUES(?,?,?,?,?,?,?,?)""",
                (supplier_code,brand_code,quantity,price,category,material,color,photo))
            db.execute("""UPDATE products SET
                photo_data=CASE WHEN COALESCE(photo_data,'')='' THEN ? ELSE photo_data END,
                category=CASE WHEN COALESCE(category,'')='' OR category='Altro' THEN ? ELSE category END,
                material=CASE WHEN COALESCE(material,'')='' THEN ? ELSE material END,
                color=CASE WHEN COALESCE(color,'')='' THEN ? ELSE color END
                WHERE supplier_code=?""",
                (photo,category,material,color,supplier_code))
        if os.path.exists(CATALOG_CSV):
            with open(CATALOG_CSV, newline="", encoding="utf-8") as fh:
                for row in csv.DictReader(fh):
                    brand=row["brand_code"].strip(); supplier=row["supplier_code"].strip()
                    excluded=1 if brand.upper().startswith("TOOL-") else 0
                    db.execute("""INSERT INTO supplier_catalog
                        (supplier_code,brand_code,category,supplier_price_usd,sale_price_eur,excluded,description,size,stone_color,plating_color,supplier_quantity,image_file,pdf_page)
                        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)
                        ON CONFLICT(supplier_code) DO UPDATE SET
                          brand_code=excluded.brand_code, category=excluded.category,
                          supplier_price_usd=excluded.supplier_price_usd, sale_price_eur=excluded.sale_price_eur,
                          excluded=excluded.excluded, description=excluded.description, size=excluded.size,
                          stone_color=excluded.stone_color, plating_color=excluded.plating_color,
                          supplier_quantity=excluded.supplier_quantity, image_file=excluded.image_file, pdf_page=excluded.pdf_page""",
                        (supplier,brand,row.get("category") or catalog_category(brand),float(row["supplier_price_usd"]),float(row["sale_price_eur"]),excluded,
                         row.get("description","").strip(),row.get("size","").strip(),row.get("stone_color","").strip(),row.get("plating_color","").strip(),
                         row.get("supplier_quantity","").strip(),row.get("image_file","").strip(),int(row.get("pdf_page") or 0)))
        db.commit()

def page(title, body, **ctx):
    inner = render_template_string(body, **ctx)
    return render_template_string(BASE, title=title, css=CSS, body=inner, app_version=APP_VERSION, db_is_ephemeral=DB_IS_EPHEMERAL)

def login_required(fn):
    @wraps(fn)
    def wrapped(*a,**k):
        return redirect(url_for("login")) if not session.get("user_id") else fn(*a,**k)
    return wrapped

def role_required(*roles):
    def decorator(fn):
        @wraps(fn)
        def wrapped(*a,**k):
            if not session.get("user_id"):
                return redirect(url_for("login"))
            if session.get("role") not in roles:
                flash("Non hai i permessi per questa operazione.")
                return redirect(url_for("dashboard"))
            return fn(*a,**k)
        return wrapped
    return decorator

def log_action(db, action, product=None, details=""):
    db.execute("INSERT INTO audit_log(user_id,username,action,product_id,product_code,details) VALUES(?,?,?,?,?,?)",(
        session.get("user_id"), session.get("user","sconosciuto"), action,
        product["id"] if product else None,
        product["brand_code"] if product else None,
        details
    ))

def photo_data(upload):
    if not upload or not upload.filename: return None
    raw=upload.read(); return f"data:{upload.mimetype or 'image/jpeg'};base64,{base64.b64encode(raw).decode()}" if raw else None

def values(form):
    brand=form["brand_code"].strip().upper()
    return (form["supplier_code"].strip().upper(),brand,int(form["quantity"]),float(form["price"].replace(",",".")),form.get("category") or infer_category(brand),form.get("material",""),form.get("color",""),form.get("size",""),form.get("stone",""),form.get("thread_type",""),form.get("notes",""),max(0,int(form.get("min_stock",1) or 1)),form.get("location","").strip(),float((form.get("cost_price","0") or "0").replace(",",".")),1 if form.get("is_new") else 0,1 if form.get("is_bestseller") else 0,form.get("model_name","").strip(),form.get("variant_group","").strip().upper())

def next_sale_number(db):
    prefix=datetime.now().strftime("V%Y%m%d")
    row=db.execute("SELECT COUNT(DISTINCT sale_number) FROM sales WHERE sale_number LIKE ?",(prefix+"%",)).fetchone()
    return f"{prefix}-{(row[0] or 0)+1:03d}"

def add_reorder_quantity(db, product_id, quantity):
    db.execute("INSERT INTO reorder_pending(product_id,quantity) VALUES(?,?) ON CONFLICT(product_id) DO UPDATE SET quantity=quantity+excluded.quantity",(product_id,quantity))

def next_order_number(db):
    prefix=datetime.now().strftime("OF%Y%m%d")
    row=db.execute("SELECT COUNT(*) FROM supplier_orders WHERE order_number LIKE ?",(prefix+"%",)).fetchone()
    return f"{prefix}-{(row[0] or 0)+1:03d}"


def next_customer_order_number(db):
    prefix=datetime.now().strftime("OC%Y%m%d")
    row=db.execute("SELECT COUNT(*) FROM customer_orders WHERE order_number LIKE ?",(prefix+"%",)).fetchone()
    return f"{prefix}-{(row[0] or 0)+1:03d}"

