@app.post("/customer-orders/<int:order_id>/confirm")
@role_required("admin","manager")
def confirm_customer_order(order_id):
    with connect() as db:
        order=db.execute("SELECT * FROM customer_orders WHERE id=?",(order_id,)).fetchone()
        if not order or order["status"]!="Nuovo": flash("Ordine non disponibile per la conferma."); return redirect(url_for("customer_orders"))
        items=db.execute("SELECT * FROM customer_order_items WHERE order_id=?",(order_id,)).fetchall()
        for item in items:
            p=db.execute("SELECT * FROM products WHERE id=?",(item["product_id"],)).fetchone()
            if not p or p["quantity"]<item["quantity"]:
                flash(f"Disponibilità insufficiente per {item['product_code']}. Ordine non confermato.")
                return redirect(url_for("customer_orders"))
        sale_number=next_sale_number(db)
        for item in items:
            p=db.execute("SELECT * FROM products WHERE id=?",(item["product_id"],)).fetchone()
            db.execute("UPDATE products SET quantity=quantity-? WHERE id=?",(item["quantity"],item["product_id"]))
            db.execute("""INSERT INTO sales(user_id,username,product_id,product_code,quantity,unit_price,sale_number,payment_method,channel,status) VALUES(?,?,?,?,?,?,?,?,?,'Confermata')""",(session.get("user_id"),session.get("user","sconosciuto"),item["product_id"],item["product_code"],item["quantity"],item["unit_price"],sale_number,"Da concordare","Online"))
            add_reorder_quantity(db,item["product_id"],item["quantity"])
        db.execute("UPDATE customer_orders SET status='Confermato' WHERE id=?",(order_id,))
        log_action(db,"Ordine cliente confermato",details=f"{order['order_number']}; vendita {sale_number}")
        db.commit()
    flash("Ordine confermato e magazzino aggiornato.")
    return redirect(url_for("customer_orders"))

@app.post("/customer-orders/<int:order_id>/cancel")
@role_required("admin","manager")
def cancel_customer_order(order_id):
    with connect() as db:
        order=db.execute("SELECT * FROM customer_orders WHERE id=?",(order_id,)).fetchone()
