@app.post("/products/<int:product_id>/duplicate")
@role_required("admin","manager")
def duplicate_product(product_id):
    with connect() as db:
        p=db.execute("SELECT * FROM products WHERE id=?",(product_id,)).fetchone()
        if not p: flash("Prodotto non trovato."); return redirect(url_for("products"))
        brand=p["brand_code"]+"-COPIA"; supplier=p["supplier_code"]+"-COPIA"; n=2
        while db.execute("SELECT 1 FROM products WHERE brand_code=? OR supplier_code=?",(brand,supplier)).fetchone():
            brand=p["brand_code"]+f"-COPIA-{n}"; supplier=p["supplier_code"]+f"-COPIA-{n}"; n+=1
        cur=db.execute("""INSERT INTO products(supplier_code,brand_code,quantity,price,category,photo_data,material,color,size,stone,thread_type,notes,active,min_stock,location,cost_price,is_new,is_bestseller,model_name,variant_group) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,1,?,?,?,?,?,?,?)""",(supplier,brand,0,p["price"],p["category"],p["photo_data"],p["material"],p["color"],p["size"],p["stone"],p["thread_type"],p["notes"],p["min_stock"],p["location"],p["cost_price"],p["is_new"],p["is_bestseller"],p["model_name"],p["variant_group"]))
        new_id=cur.lastrowid; np=db.execute("SELECT * FROM products WHERE id=?",(new_id,)).fetchone(); log_action(db,"Prodotto duplicato",np,f"Da {p['brand_code']}"); db.commit()
    flash("Copia creata: completa i codici e la quantità.")
    return redirect(url_for("edit_product",product_id=new_id))

